SELECT buoy_name, location
FROM buoys
WHERE status = 'active';

SELECT buoy_name 
FROM buoys 
ORDER BY buoy_name ASC;

SELECT MAX(value) AS highest_temperature
FROM datasets
WHERE buoy_id = 1 AND type_id = (SELECT type_id FROM data_types WHERE type_name = 'Temperature');

SELECT buoy_name, location, deployment_date
FROM buoys
ORDER BY deployment_date DESC;

SELECT buoy_name, location
FROM buoys
ORDER BY buoy_name ASC;
